mapper.insert:
insert into scrim(
	scrim_id, scrim_tournament, scrim_red_team, scrim_red_score,
	scrim_blue_team, scrim_blue_score, scrim_date, scrim_created_by,
	scrim_hour, scrim_match_type
) values(
 scrim_seq.nextval, #{scrimTournament}, #{scrimRedTeam},#{scrimRedScore},
 #{scrimBlueTeam},#{scrimBlueScore},#{scrimDate},#{scrimCreatedBy},#{scrimHour},#{scrimMatchType}
)

mapper.select:
select * from (
	select rownum rn, TMP.* from(
		select * from scrim_list
		where scrim_tournament = #{keyword}
		order by scrim_date desc, scrim_hour desc, scrim_id desc
	) TMP
) where rn between #{begin} and #{end}

select * from scrim_record
where scrim_tournament = #{scrimTournament}
order by scrim_win_count desc

select * from scrim_vs_record
where scrim_tournament = #{scrimTournament}
	and scrim_team = #{scrimTeam}
	order by vs_win_count desc

    select * from (
        select TMP.*,  rownum rn
        from (
            select sm.*, count(*) over() as total_count
            	from scrim_mypage sm
            	where sm.scrim_created_by = #{keyword}
            	order by sm.scrim_date desc, sm.scrim_hour desc, sm.scrim_id desc
        ) TMP
	) where rn between #{begin} and #{end}
